commit 4b663521c2f63cb494798cc528b9420249ffbd85
Author: Sam Gross <colesbury@gmail.com>
Date:   Mon Feb 6 09:51:32 2023 -0800

    mimalloc: check if tstate is NULL

    Fixes #105
---
 Objects/mimalloc/page.c | 10 +++++++---
 1 file changed, 7 insertions(+), 3 deletions(-)

diff --git a/Objects/mimalloc/page.c b/Objects/mimalloc/page.c
index c4eed9b832..f1ae8315d4 100644
--- a/Objects/mimalloc/page.c
+++ b/Objects/mimalloc/page.c
@@ -341,7 +341,10 @@ void _mi_page_unfull(mi_page_t* page) {
   mi_heap_t* heap = mi_page_heap(page);
   if (page->tag == mi_heap_tag_gc) {
     PyThreadState *tstate = _PyThreadState_GET();
-    _Py_atomic_add_ssize(&tstate->interp->gc.gc_live, -page->capacity);
+    // tstate may be NULL during interpreter finalization
+    if (tstate) {
+      _Py_atomic_add_ssize(&tstate->interp->gc.gc_live, -page->capacity);
+    }
   }
   mi_page_queue_t* pqfull = &heap->pages[MI_BIN_FULL];
   mi_page_set_in_full(page, false); // to get the right queue
@@ -361,8 +364,9 @@ static void mi_page_to_full(mi_page_t* page, mi_page_queue_t* pq) {

   if (page->tag == mi_heap_tag_gc) {
     PyThreadState *tstate = _PyThreadState_GET();
-    struct _gc_runtime_state *gcstate = &tstate->interp->gc;
-    _Py_atomic_add_ssize(&gcstate->gc_live, page->capacity);
+    if (tstate) {
+      _Py_atomic_add_ssize(&tstate->interp->gc.gc_live, page->capacity);
+    }
   }
 }

commit 5a7b97eab0d3da19fbfbc4b3595d2f902725aaaf
Author: Sam Gross <colesbury@gmail.com>
Date:   Tue Dec 27 17:42:35 2022 -0800

    atomic: add bulitin (GCC) atomics

    Previously, we used the frozen pyconfig.h feature flags to determine
    which atomic implementation to use. This did not work for the SciPy
    Windows build because it builds with GCC against a Windows Python, which
    effectively assumed MSVC.

    This moves the feature detection later when pyatomic.h is included and
    also adds an implementation for GCC builtin atomics (also implemented by
    Clang) that don't require compiling with "--std=c11".
---
 Include/pyatomic.h     |  28 +++-
 Include/pyatomic_gcc.h | 433 +++++++++++++++++++++++++++++++++++++++++++++++++
 Include/pyatomic_msc.h |  43 +++++
 Include/pyatomic_std.h |  41 +++++
 4 files changed, 544 insertions(+), 1 deletion(-)

diff --git a/Include/pyatomic.h b/Include/pyatomic.h
