commit 2dcbadc25d58ff854b35406512971b5fc69793de
Author: Sam Gross <colesbury@gmail.com>
Date:   Mon Jun 13 12:50:09 2022 -0700

    frame: fix thread-safety issue when accessing f_lineno

    It wasn't safe to access f_lineno from the thread that doesn't won the
    frame. This can happen, for example, when calling sys.current_frames()
    and accessing another thread's frames (such as for profiling purposes).

    See #66
---
 Objects/frameobject.c | 6 +++++-
 1 file changed, 5 insertions(+), 1 deletion(-)

diff --git a/Objects/frameobject.c b/Objects/frameobject.c
index c386a5b5f1..b720432b39 100644
--- a/Objects/frameobject.c
+++ b/Objects/frameobject.c
@@ -43,7 +43,11 @@ PyFrame_GetLineNumber(PyFrameObject *f)
         return f->f_lineno;
     }
     struct ThreadState *ts = f->f_ts;
-    if (ts && ts->ts && !ts->ts->tracing) {
+    PyThreadState *tstate = PyThreadState_GET();
+    // We are supposed to update the current line number when we're not tracing,
+    // but that's not safe to do from another thread. If we're not in the owning
+    // thread, just use the potentially stale line number.
+    if (ts && ts->ts == tstate && !tstate->tracing) {
         // update f->f_lasti
         vm_frame_at_offset(ts, f->f_offset);
     }

