 1 file changed, 2 insertions(+), 2 deletions(-)

diff --git a/Modules/_threadmodule.c b/Modules/_threadmodule.c
index df94586e06..e6a2d0bc92 100644
--- a/Modules/_threadmodule.c
+++ b/Modules/_threadmodule.c
@@ -174,8 +174,8 @@ lock_PyThread_release_lock(lockobject *self, PyObject *Py_UNUSED(ignored))
         return NULL;
     }

-    PyThread_release_lock(self->lock_lock);
     self->locked = 0;
+    PyThread_release_lock(self->lock_lock);
     Py_RETURN_NONE;
 }

@@ -1351,8 +1351,8 @@ release_sentinel(void *wr_raw)
         assert(Py_IS_TYPE(obj, &Locktype));
         lock = (lockobject *) obj;
         if (lock->locked) {
-            PyThread_release_lock(lock->lock_lock);
             lock->locked = 0;
+            PyThread_release_lock(lock->lock_lock);
         }
         Py_DECREF(obj);
     }

